class Solution(object):
    def largestLocal(self, grid):
        n = len(grid)
        result = []
        for i in range(n - 2):
            row = []
            for j in range(n - 2):
                max_val = max(grid[i+di][j+dj] for di in range(3) for dj in range(3))
                row.append(max_val)
            result.append(row)
        return result
